// Method 1: Lambda expression
Comparator<String> byLength = (s1, s2) -> s1.length() - s2.length();

// Method 2: Method reference with comparing
Comparator<String> byLength2 = Comparator.comparingInt(String::length);

// Method 3: Using Collections utility
Collections.sort(list, byLength);

// Method 4: Using List sort (Java 8+)
list.sort(byLength2);

// Example usage
List<String> words = Arrays.asList("cat", "elephant", "a", "dog");
words.sort(Comparator.comparingInt(String::length));
// Output: [a, cat, dog, elephant]

class Employee {
 private String name;
 private int salary;
 private String department;

 // constructors, getters
}

// Sort by department (asc), then salary (desc), then name (asc)
Comparator<Employee> complexSort = Comparator
 .comparing(Employee::getDepartment) // Primary: department ascending
 .thenComparing(Comparator.comparingInt(Employee::getSalary).reversed()) // Secondary: salary descending
 .thenComparing(Employee::getName); // Tertiary: name ascending

List<Employee> employees = new ArrayList<>();
// add employees...
employees.sort(complexSort);

// Alternative using Collections
Collections.sort(employees, complexSort);

class Person {
 private String name;
 private Integer age;
 // constructors, getters
}

List<Person> people = Arrays.asList(
 new Person("Alice", 25),
 null,
 new Person("Bob", null),
 null,
 new Person("Charlie", 30)
);

// Handle nulls in the list - put all null Persons at end
// Within non-null persons, sort by name (case-insensitive)
Comparator<Person> nullSafeComparator = Comparator
 .nullsLast(Comparator.comparing(Person::getName, String.CASE_INSENSITIVE_ORDER));

people.sort(nullSafeComparator);

// For handling null ages within Person objects:
Comparator<Person> withNullAgeHandling = Comparator
 .nullsLast(Comparator.comparing(Person::getName))
 .thenComparing(Comparator.nullsLast(Comparator.comparingInt(Person::getAge)));

// Using nullsFirst for nulls at beginning:
Comparator<Person> nullsAtStart = Comparator
 .nullsFirst(Comparator.comparing(Person::getName));
